   454→// makeHTTPRequest is a helper function to make HTTP requests to the API
   455→func makeHTTPRequest(method, url string, body io.Reader) ([]byte, error) {
   456→	req, err := http.NewRequest(method, url, body)
   457→	if err != nil {
   458→		return nil, err
   459→	}
   460→
   461→	if body != nil {
   462→		req.Header.Set("Content-Type", "application/json")
   463→	}
   464→
   465→	client := &http.Client{Timeout: 30 * time.Second}
   466→	resp, err := client.Do(req)
   467→	if err != nil {
   468→		return nil, err
   469→	}
   470→	defer resp.Body.Close()
   471→
   472→	responseBody, err := io.ReadAll(resp.Body)
   473→	if err != nil {
   474→		return nil, err
   475→	}
   476→
   477→	// Check for HTTP errors
   478→	if resp.StatusCode >= 400 {
   479→		var errorResponse map[string]interface{}
   480→		if json.Unmarshal(responseBody, &errorResponse) == nil {
   481→			if errorMsg, ok := errorResponse["error"].(string); ok {
   482→				return nil, fmt.Errorf("API error (status %d): %s", resp.StatusCode, errorMsg)
   483→			}
   484→		}
   485→		return nil, fmt.Errorf("API error (status %d): %s", resp.StatusCode, string(responseBody))
   486→	}
   487→
   488→	return responseBody, nil
   489→}
