    16→// Handler handles LLM model registry operations
    17→type Handler struct {
    18→	storage   storage.Storage
    19→	validator *validation.LLMModelValidator
    20→}
    21→
    22→// NewHandler creates a new LLM handler
    23→func NewHandler(storage storage.Storage) *Handler {
    24→	return &Handler{
    25→		storage:   storage,
    26→		validator: validation.NewLLMModelValidator(),
    27→	}
    28→}
