    30→// RegisterRoutes registers all LLM model routes
    31→func (h *Handler) RegisterRoutes(app *fiber.App) {
    32→	// Create v1 API group
    33→	v1 := app.Group("/v1")
    34→	llms := v1.Group("/llms")
    35→	models := llms.Group("/models")
    36→
    37→	// Model management routes
    38→	models.Get("/", h.ListModels)             // GET /v1/llms/models
    39→	models.Get("/:id", h.GetModel)            // GET /v1/llms/models/{id}
    40→	models.Post("/", h.CreateModel)           // POST /v1/llms/models
    41→	models.Put("/:id", h.UpdateModel)         // PUT /v1/llms/models/{id}
    42→	models.Delete("/:id", h.DeleteModel)      // DELETE /v1/llms/models/{id}
    43→	models.Get("/:id/stats", h.GetModelStats) // GET /v1/llms/models/{id}/stats
    44→}
