    46→// ListModels returns a list of LLM models
    47→func (h *Handler) ListModels(c *fiber.Ctx) error {
    48→	ctx := context.Background()
    49→
    50→	// Parse query parameters
    51→	provider := c.Query("provider", "")
    52→	capability := c.Query("capability", "")
    53→	limit, _ := strconv.Atoi(c.Query("limit", "20"))
    54→	offset, _ := strconv.Atoi(c.Query("offset", "0"))
    55→
    56→	// Create filter options
    57→	filterOptions := storage.ListOptions{
    58→		Prefix:  "llms/models/",
    59→		MaxKeys: limit,
    60→	}
    61→
    62→	// List objects from storage
    63→	objects, err := h.storage.List(ctx, filterOptions)
    64→	if err != nil {
    65→		return c.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
    66→			"error": fmt.Sprintf("failed to list models: %v", err),
    67→		})
    68→	}
    69→
    70→	// Load and filter models
    71→	modelsList := make([]*models.LLMModel, 0)
    72→	for i, obj := range objects {
    73→		// Apply offset
    74→		if i < offset {
    75→			continue
    76→		}
    77→
    78→		// Apply limit
    79→		if len(modelsList) >= limit {
    80→			break
    81→		}
    82→
    83→		// Get model data
    84→		reader, err := h.storage.Get(ctx, obj.Key)
    85→		if err != nil {
    86→			continue // Skip invalid models
    87→		}
    88→
    89→		var model models.LLMModel
    90→		decoder := json.NewDecoder(reader)
    91→		if err := decoder.Decode(&model); err != nil {
    92→			reader.Close()
    93→			continue // Skip invalid models
    94→		}
    95→		reader.Close()
    96→
    97→		// Apply filters
    98→		if provider != "" && model.Provider != provider {
    99→			continue
   100→		}
   101→
   102→		if capability != "" && !model.HasCapability(capability) {
   103→			continue
   104→		}
   105→
   106→		modelsList = append(modelsList, &model)
   107→	}
   108→
   109→	return c.JSON(fiber.Map{
