   130→// ListModelFilter represents filter options for listing models
   131→type ListModelFilter struct {
   132→	Provider   string
   133→	Capability string
   134→	Limit      int
   135→	Offset     int
   136→}
   137→
   138→// ListModels lists LLM models with optional filtering
   139→func (s *LLMModelStorage) ListModels(ctx context.Context, filter ListModelFilter) ([]*models.LLMModel, int, error) {
   140→	// Set default limit if not specified
   141→	if filter.Limit <= 0 {
   142→		filter.Limit = 20
   143→	}
   144→
   145→	// List objects from storage
   146→	listOptions := ListOptions{
   147→		Prefix:  "llms/models/",
   148→		MaxKeys: filter.Limit + filter.Offset, // Get more to handle filtering and offset
   149→	}
   150→
   151→	objects, err := s.storage.List(ctx, listOptions)
   152→	if err != nil {
   153→		return nil, 0, fmt.Errorf("failed to list models: %w", err)
   154→	}
   155→
   156→	// Load and filter models
   157→	modelsList := make([]*models.LLMModel, 0)
   158→	processed := 0
   159→
   160→	for _, obj := range objects {
   161→		// Get model data
   162→		reader, err := s.storage.Get(ctx, obj.Key)
   163→		if err != nil {
   164→			continue // Skip invalid models
   165→		}
   166→
   167→		var model models.LLMModel
   168→		decoder := json.NewDecoder(reader)
   169→		if err := decoder.Decode(&model); err != nil {
   170→			reader.Close()
   171→			continue // Skip invalid models
   172→		}
   173→		reader.Close()
   174→
   175→		// Apply provider filter
   176→		if filter.Provider != "" && model.Provider != filter.Provider {
   177→			continue
   178→		}
   179→
   180→		// Apply capability filter
   181→		if filter.Capability != "" && !model.HasCapability(filter.Capability) {
   182→			continue
   183→		}
   184→
   185→		// Apply offset
   186→		if processed < filter.Offset {
   187→			processed++
   188→			continue
   189→		}
   190→
   191→		// Apply limit
   192→		if len(modelsList) >= filter.Limit {
   193→			break
   194→		}
   195→
   196→		modelsList = append(modelsList, &model)
   197→		processed++
   198→	}
   199→
   200→	return modelsList, len(objects), nil
   201→}
