   284→// RestoreModels restores models from a backup
   285→func (s *LLMModelStorage) RestoreModels(ctx context.Context, backupReader io.Reader, overwrite bool) error {
   286→	// Decode backup data
   287→	var models []*models.LLMModel
   288→	decoder := json.NewDecoder(backupReader)
   289→	if err := decoder.Decode(&models); err != nil {
   290→		return fmt.Errorf("failed to decode backup data: %w", err)
   291→	}
   292→
   293→	// Restore each model
   294→	for _, model := range models {
   295→		// Check if model exists
   296→		exists, err := s.ModelExists(ctx, model.ID)
   297→		if err != nil {
   298→			return fmt.Errorf("failed to check model existence during restore: %w", err)
   299→		}
   300→
   301→		if exists && !overwrite {
   302→			continue // Skip existing models if not overwriting
   303→		}
   304→
   305→		// Create or update model
   306→		if exists {
   307→			if err := s.UpdateModel(ctx, model); err != nil {
   308→				return fmt.Errorf("failed to update model %s during restore: %w", model.ID, err)
   309→			}
   310→		} else {
   311→			if err := s.CreateModel(ctx, model); err != nil {
   312→				return fmt.Errorf("failed to create model %s during restore: %w", model.ID, err)
   313→			}
   314→		}
   315→	}
   316→
   317→	return nil
   318→}
